sys_ux_client_script_include.script:
function include({imports}) {

    function isDataField(field) {
        return field.isDataField !== false;
    }

    function resolveValidationType(field, rule) {
        const ruleType = rule && rule.type != null && String(rule.type) !== '' ?
            String(rule.type).toLowerCase() :
            '';
        if (ruleType) {
            return ruleType;
        }
        const fieldType = field && field.type != null && String(field.type) !== '' ?
            String(field.type).toLowerCase() :
            '';
        return fieldType || '';
    }

    function hasValidationConfig(rule) {
        if (!rule || typeof rule !== 'object') {
            return false;
        }
        return rule.mandatory === true ||
            (rule.type != null && String(rule.type) !== '') ||
            rule.minLength != null ||
            (rule.maxLength != null && rule.maxLength > 0) ||
            (Array.isArray(rule.allowedValues) && rule.allowedValues.length > 0);
    }

    function isMandatory(field, rule) {
        return rule.mandatory === true || field.mandatory === true;
    }

    function fieldErrorMessage(field, message) {
        if (message) {
            field.messages = [{
                message: message,
                type: 'error'
            }];
        } else {
            delete field.messages;
        }
    }

    function validateChoice(field) {
        if (!Array.isArray(field.choices) || field.choices.length < 1) {
            fieldErrorMessage(field, 'No valid choices are configured for this field');
            return false;
        }
        const value = field.value === null || field.value === undefined ?
            '' :
            String(field.value);
        for (const choice of field.choices) {
            if (choice != null && String(choice.value) === value) {
                return true;
            }
        }
        fieldErrorMessage(field, 'Value not permitted');
        return false;
    }

    function validateField(field) {
        if (!field || typeof field !== 'object') {
            return true;
        }
        fieldErrorMessage(field, null);
        if (!isDataField(field)) {
            return true;
        }
        if (field.readonly === true) {
            return true;
        }

        const rule = field.nfValidation || null;
        if (!hasValidationConfig(rule)) {
            return true;
        }
        const ruleObj = rule;
        const type = resolveValidationType(field, ruleObj);
        const strVal = (field.value === null || field.value === undefined || field.value === '') ?
            null :
            String(field.value);

        if (strVal === null) {
            if (isMandatory(field, ruleObj)) {
                fieldErrorMessage(field, 'Field is mandatory');
                return false;
            }
            return true;
        }

        let checkLength = true;
        let checkAllowedValues = true;
        switch (type) {
            case 'integer':
                if (!/^-?\d+$/.test(strVal)) {
                    fieldErrorMessage(field, 'Value must be an integer');
                    return false;
                }
                break;
            case 'decimal':
                if (!/^-?\d+(\.\d+)?$/.test(strVal)) {
                    fieldErrorMessage(field, 'Value must be a number');
                    return false;
                }
                break;
            case 'boolean':
                if (['true', 'false', '1', '0', 'y', 'n'].indexOf(strVal.toLowerCase()) === -1) {
                    fieldErrorMessage(field, 'Value must be a boolean');
                    return false;
                }
                return true; // nothing else applies
            case 'date':
            case 'glide_date':
            case 'glide_date_time':
                if (isNaN(new Date(strVal).getTime())) {
                    fieldErrorMessage(field, 'Value must be a valid date');
                    return false;
                }
                checkLength = false;
                break;
            case 'choice':
                checkAllowedValues = false;
                checkLength = false;
                return validateChoice(field);
            default:
                break;
        }

        // Allowed values (fail fast)
        if (checkAllowedValues && Array.isArray(ruleObj.allowedValues) && ruleObj.allowedValues.length) {
            if (ruleObj.allowedValues.indexOf(strVal) === -1) {
                fieldErrorMessage(field, 'Value not permitted');
                return false;
            }
        }

        // Length checks (fail fast)
        if (checkLength) {
            if (ruleObj.minLength != null && strVal.length < ruleObj.minLength) {
                fieldErrorMessage(field, 'Must be at least ' + ruleObj.minLength + ' characters long');
                return false;
            }
            if (ruleObj.maxLength > 0 && strVal.length > ruleObj.maxLength) {
                fieldErrorMessage(field, 'Exceeds maximum length: ' + ruleObj.maxLength);
                return false;
            }
        }
/*This is now handled using ootb regex evaluation
        // Regex (final gate)
        let rx = null;
        if (typeof rule.regex === 'string' && rule.regex.length) {
            try {
                rx = new RegExp(rule.regex);
            } catch (e1) {
                console.warn('Regex is invalid', rule.regex);
                return true;
            }
            if (!rx.test(strVal)) {
                fieldErrorMessage(field, 'Does not match regex');
                return false;
            }
        }*/
        return true;
    }

    function validateAllFields(fields) {
        const out = {};
        let allOk = true;
        Object.keys(fields || {}).forEach(function(key) {
            const field = fields[key];
            const result = validateField(field);
            if (!result) {
                allOk = false;
            }
            out[key] = { name: field.name, valid: result };
        });
        return { fields: out, allOk };
    }

    function cloneFieldsMap(fields) {
        const cloned = {};
        Object.keys(fields || {}).forEach(function(key) {
            const field = fields[key];
            cloned[key] = field && typeof field === 'object' ?
                Object.assign({}, field) :
                field;
        });
        return cloned;
    }

    function canProcess(state, vr) {
        const onLast = state.currentScreenNumber === state.screenCount;
        return onLast && !state.isProcessed && vr && vr.allOk === true;
    }
    /* The old way (for reference)

      Use the same UX events as @servicenow/now-record-form-connected (sys_ux_event export):
        SHOW: NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#SHOW_FIELD_MESSAGE  payload: fieldName, type, message
        HIDE: NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#HIDE_FIELD_MESSAGE  payload: fieldName, clearAll

    function fieldErrorMessage(field, message) {
        const SHOW_EVENT = 'sn_now_record_form.NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#SHOW_FIELD_MESSAGE';
        const HIDE_EVENT = 'sn_now_record_form.NOW_RECORD_FORM_SECTION_COLUMN_LAYOUT#HIDE_FIELD_MESSAGE';
        if (message) {
            api.emit(SHOW_EVENT, {
                fieldName: field.name,
                type: 'error',
                message: message
            });
        } else {
            api.emit(HIDE_EVENT, {
                fieldName: field.name,
                clearAll: false
            });
        }
    }
    */

    return {
        validateField,
        validateAllFields,
        cloneFieldsMap,
        canProcess
    };
}
